+    #[test]
+    fn test_pragma_connection_stats_counts_prepare_cache_hits() {
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("pool-prepare-cache-hits.db");
+        let db_path = db_path.to_string_lossy().into_owned();
+
+        let conn = Connection::open(&db_path).unwrap();
+        let _first = conn.prepare("SELECT 1;").unwrap();
+        let _second = conn.prepare("SELECT 1;").unwrap();
+
+        let stats = txn_metrics_map(&conn.query("PRAGMA fsqlite.connection_stats;").unwrap());
+        assert_eq!(stats.get("pool_size_estimate"), Some(&1));
+        assert!(
+            stats
+                .get("prepare_calls_total")
+                .copied()
+                .unwrap_or_default()
+                >= 2,
+            "prepare_calls_total should count successful prepare() cache hits as calls",
+        );
+        assert!(
+            stats
+                .get("current_connection_prepare_calls")
+                .copied()
+                .unwrap_or_default()
+                >= 2,
+            "per-connection prepare counts should include cached prepares",
+        );
+    }
